/* WikiTrace — Firefox MV2 compatibility shim
 *
 * Firefox MV2 exposes chrome.browserAction instead of chrome.action (MV3).
 * This shim aliases chrome.action → chrome.browserAction so background.js
 * works unchanged in both Chrome MV3 and Firefox MV2.
 *
 * All other chrome.* APIs (storage, tabs, runtime, webNavigation) are
 * natively available in Firefox under the chrome namespace, so no further
 * shim is needed for the current WikiTrace feature set.
 *
 * When Feature B (Google Sign-In) is implemented, replace this file with
 * the full Mozilla webextension-polyfill and update chrome.identity calls
 * to use browser.identity as described in ROADMAP step C3.
 */
(function () {
  if (typeof chrome === 'undefined') return;
  if (chrome.action) return;           // Chrome MV3 / Firefox MV3: already present
  if (chrome.browserAction) {
    chrome.action = chrome.browserAction; // Firefox MV2: remap browserAction → action
  }
})();
